        foreach ($details as $detail) {
            $candidate = \App\Candidate::where('enrolmentno', $detail['enrolmentno'])->first();

            if(!is_null($candidate)) {
                $subject = \App\Subject::where('scode', $detail['scode'])->first();

                if(!is_null($subject)) {
                    $application = \App\Application::where('exam_id', $detail['exam_id'])
                        ->where('candidate_id', $candidate->id)->where('subject_id', $subject->id)->first();

                    if(!is_null($application)) {
                        $exammarksheetdetail = \App\Exammarksheetdetail::where('exam_id', $application->exam_id)
                            ->where('programme_id', $application->subject->programme_id)
                            ->where('academicyear_id', $candidate->approvedprogramme->academicyear_id)
                            ->where('term', $application->subject->syear)
                            ->first();

                        if(!is_null($exammarksheetdetail)) {
                            $application->update([
                                'examtype_id' => $exammarksheetdetail->examtype_id,
                                'exammarksheetdetail_id' => $exammarksheetdetail->id,
                                'marksheet_number' => $detail['marksheet_number'],
                            ]);
                        }
                    }
                }
            }

            unset($candidate);
            unset($subject);
            unset($application);
            unset($exammarksheetdetail);
            unset($detail);
        }
